+    #[test]
+    fn token_id_debug_clone_hash() {
+        use std::collections::HashSet;
+        let id = TokenId("ct-test-001".to_string());
+        let dbg = format!("{:?}", id);
+        assert!(dbg.contains("ct-test-001"));
+        let cloned = id.clone();
+        assert_eq!(id, cloned);
+        let mut set = HashSet::new();
+        set.insert(id.clone());
+        set.insert(id.clone());
+        assert_eq!(set.len(), 1);
+    }
